scripts.content:
extends StaticBody3D

class_name LootableContainer

signal container_opened
signal container_closed
signal loot_generated(items: Array[Dictionary])
signal loot_collected(item: Dictionary)

@export var loot_table_path: String = "{{loot_table_path}}"
@export var respawn_time: float = {{respawn_time}}

var _is_open: bool = false
var _is_empty: bool = false
var _loot_items: Array[Dictionary] = []
var _respawn_timer: float = 0.0
var _open_progress: float = 0.0

@onready var _mesh: MeshInstance3D = $MeshInstance3D
@onready var _lid: MeshInstance3D = $Lid
@onready var _interaction_area: Area3D = $InteractionArea
@onready var _particles: GPUParticles3D = $OpenParticles

func _ready():
	add_to_group("interactable")
	add_to_group("lootable")

	if _interaction_area:
		_interaction_area.body_entered.connect(_on_body_entered)
		_interaction_area.body_exited.connect(_on_body_exited)

	# Generate initial loot
	_generate_loot()

func get_interaction_prompt() -> String:
	if _is_empty and respawn_time > 0:
		return "Empty"
	return "{{interaction_prompt}}"

func interact(player: Node) -> void:
	if _is_open:
		_close()
		return

	if _is_empty:
		return

	_open()

func _open() -> void:
	_is_open = true
	container_opened.emit()

	if _particles:
		_particles.emitting = true

func _close() -> void:
	_is_open = false
	container_closed.emit()

	if _loot_items.is_empty():
		_is_empty = true
		if respawn_time > 0:
			_respawn_timer = respawn_time

func collect_all(player: Node) -> Array[Dictionary]:
	var collected := _loot_items.duplicate()
	_loot_items.clear()
	for item in collected:
		_grant_item(player, item)
		loot_collected.emit(item)
	return collected

func collect_item(index: int, player: Node) -> Dictionary:
	if index < 0 or index >= _loot_items.size():
		return {}
	var item := _loot_items[index]
	_loot_items.remove_at(index)
	_grant_item(player, item)
	loot_collected.emit(item)
	return item

func get_loot_items() -> Array[Dictionary]:
	return _loot_items

func is_open() -> bool:
	return _is_open

func is_empty() -> bool:
	return _is_empty

func force_respawn() -> void:
	_respawn_timer = 0.0
	_is_empty = false
	_generate_loot()

func _process(delta: float) -> void:
	_respawn_timer -= delta
	if _respawn_timer <= 0 and _is_empty:
		force_respawn()

	# Lid animation
	var target: float = 1.0 if _is_open else 0.0
	var speed := 1.0 / max({{open_animation_duration}}, 0.05)
	_open_progress = move_toward(_open_progress, target, delta * speed)

	if _lid and _mesh:
		_lid.position.y = _mesh.position.y + lerp(0.0, 1.2, ease(_open_progress, -1.5))

func _generate_loot() -> void:
	_loot_items = LootTable.roll(loot_table_path)
	if _loot_items.is_empty():
		_is_empty = true
	else:
		_is_empty = false
	loot_generated.emit(_loot_items)

func _grant_item(player: Node, item: Dictionary) -> void:
	var item_id := item.get("id", "")
	var count := item.get("count", 1)

	var inv := player.get_parent().find_child("InventoryManager", true, false)
	if inv and inv.has_method("add_item"):
		inv.add_item(item_id, count)

func _on_body_entered(body: Node) -> void:
	if body.is_in_group("player"):
		# Optional: show a nearby prompt
		pass

func _on_body_exited(body: Node) -> void:
	if body.is_in_group("player"):
		if _is_open:
			_close()

func serialize() -> Dictionary:
	return {
		"is_open": _is_open,
		"is_empty": _is_empty,
		"loot_items": _loot_items,
		"respawn_timer": _respawn_timer,
	}

func deserialize(data: Dictionary) -> void:
	_is_open = data.get("is_open", false)
	_is_empty = data.get("is_empty", false)
	_loot_items = data.get("loot_items", [])
	_respawn_timer = data.get("respawn_timer", 0.0)
